// TestAttack_RegisterCommand_RaceCondition tests concurrent registration and listing
func TestAttack_RegisterCommand_RaceCondition(t *testing.T) {
	ClearGlobalCommands()
	defer ClearGlobalCommands()

	const writers = 10
	const readers = 20
	const iterations = 100

	var wg sync.WaitGroup
	wg.Add(writers + readers)

	// Start writers - registering commands concurrently
	for w := 0; w < writers; w++ {
		go func(workerID int) {
			defer wg.Done()
			for i := 0; i < iterations; i++ {
				name := stringFromInt("cmd", workerID*iterations+i)
				executor := newMockExecutor(`^/test$`, "", false)
				_ = RegisterCommand(name, executor)
			}
		}(w)
	}

	// Start readers - listing commands concurrently
	for r := 0; r < readers; r++ {
		go func() {
			defer wg.Done()
			for i := 0; i < iterations; i++ {
				commands := ListRegisteredCommands()
				// Just access the map, verify it doesn't panic
				_ = len(commands)
			}
		}()
	}

	wg.Wait()

	// Verify all commands were registered
	commands := ListRegisteredCommands()
	assert.Equal(t, writers*iterations, len(commands))
}

// TestAttack_ClearGlobalCommands_RaceWithRegistration tests clearing during registration
