// TestAttack_CommandContext_NilFields tests that executors handle nil fields gracefully
func TestAttack_CommandContext_NilFields(t *testing.T) {
	executor := newMockExecutor(`^/test$`, "", false)

	ctx := context.Background()
	msg := agentic.UserMessage{
		MessageID:   "msg-1",
		ChannelType: "cli",
		ChannelID:   "test",
		UserID:      "user-1",
	}

	tests := []struct {
		name   string
		cmdCtx *CommandContext
	}{
		{
			name: "nil NATSClient",
			cmdCtx: &CommandContext{
				NATSClient:    nil,
				LoopTracker:   NewLoopTracker(),
				Logger:        nil,
				HasPermission: func(string, string) bool { return true },
			},
		},
		{
			name: "nil Logger",
			cmdCtx: &CommandContext{
				NATSClient:    nil,
				LoopTracker:   NewLoopTracker(),
				Logger:        nil,
				HasPermission: func(string, string) bool { return true },
			},
		},
		{
			name: "nil HasPermission",
			cmdCtx: &CommandContext{
				NATSClient:    nil,
				LoopTracker:   NewLoopTracker(),
				Logger:        nil,
				HasPermission: nil,
			},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			// Mock executor validates ctx and cmdCtx are not nil,
			// but doesn't validate individual fields.
			// Real executors should handle nil fields gracefully.
			_, err := executor.Execute(ctx, tt.cmdCtx, msg, []string{}, "")
			assert.NoError(t, err, "executor should handle nil fields")
		})
	}
}

// TestAttack_CancelledContext_InExecutor tests executor behavior with cancelled context
func TestAttack_CancelledContext_InExecutor(t *testing.T) {
	executor := newMockExecutor(`^/test$`, "", false)

	ctx, cancel := context.WithCancel(context.Background())
	cancel() // Cancel immediately

	cmdCtx := &CommandContext{
		LoopTracker: NewLoopTracker(),
	}

	msg := agentic.UserMessage{
		MessageID:   "msg-1",
		ChannelType: "cli",
		ChannelID:   "test",
		UserID:      "user-1",
	}

	// Execute with cancelled context
	done := make(chan struct{})
	go func() {
		defer close(done)
		_, _ = executor.Execute(ctx, cmdCtx, msg, []string{}, "")
	}()

	// Should complete quickly (not hang)
	select {
	case <-done:
		// Success - completed
	case <-time.After(5 * time.Second):
		t.Fatal("executor hung on cancelled context")
	}

	// Verify context was cancelled
	assert.Equal(t, context.Canceled, ctx.Err())
}

