// TestAttack_ListRegisteredCommands_MapMutation tests that external mutation doesn't affect registry
func TestAttack_ListRegisteredCommands_MapMutation(t *testing.T) {
	ClearGlobalCommands()
	defer ClearGlobalCommands()

	// Register initial commands
	for i := 0; i < 5; i++ {
		name := stringFromInt("cmd", i)
		executor := newMockExecutor(`^/test$`, "", false)
		err := RegisterCommand(name, executor)
		require.NoError(t, err)
	}

	// Get list and mutate it
	list1 := ListRegisteredCommands()
	require.Len(t, list1, 5)

	// Add fake entries
	for i := 0; i < 10; i++ {
		name := stringFromInt("fake", i)
		list1[name] = newMockExecutor(`^/fake$`, "", false)
	}

	// Delete real entries
	delete(list1, "cmd0")
	delete(list1, "cmd1")

	// Get fresh list
	list2 := ListRegisteredCommands()

	// Should be unchanged
	assert.Len(t, list2, 5, "registry was mutated by external map modification")
	assert.Contains(t, list2, "cmd0")
	assert.Contains(t, list2, "cmd1")
	assert.NotContains(t, list2, "fake0")
}
